import createRequestOptions from"./createRequestOptions.js";import{handleResponse,handleError}from"./handleResponse.js";export default function zlFetch(e,t){return fetchInstance({url:e,...t})}const methods=["get","post","put","patch","delete"];for(const c of methods)zlFetch[c]=function(e,t){return zlFetch(e,t=Object.assign({method:c},t))};async function fetchInstance(t){const e=await getFetch(),n=createRequestOptions({...t,fetch:e});return delete n.fetch,delete n.auth,delete n.debug,delete n.returnError,e.fetch(n.url,n).then(e=>handleResponse(e,t)).then(e=>t.debug?{...e,debug:debugHeaders(n)}:e).catch(handleError)}async function getFetch(){var e;return"undefined"==typeof fetch?{fetch:(e=await import("node-fetch")).default,Headers:e.Headers}:{fetch:window.fetch.bind(window),Headers:window.Headers}}function debugHeaders(e){const t=Object.assign({},e),n={};for(var[r,o]of t.headers)n[r]=o;return t.headers=n,t}export{getFetch};